function testComparator(version: Version, operator: Comparator["operator"], operand: Version) {
    const cmp = version.compareTo(operand);
    switch (operator) {
        case "<":
            return cmp < 0;
        case "<=":
            return cmp <= 0;
        case ">":
            return cmp > 0;
        case ">=":
            return cmp >= 0;
        case "=":
            return cmp === 0;
        default:
            return Debug.assertNever(operator);
    }
}

